<script setup lang="ts">
import gsap from "gsap";

const visible = ref(true);
const overlayRef = useTemplateRef<HTMLDivElement>("overlayRef");
const svgRef = useTemplateRef<SVGSVGElement>("svgRef");

let tl: gsap.core.Timeline | null = null;

onMounted(() => {
  if (window.matchMedia("(prefers-reduced-motion: reduce)").matches) {
    visible.value = false;
    return;
  }

  const paths =
    svgRef.value?.querySelectorAll<SVGPathElement>(".signature-path") ?? [];

  paths.forEach((path) => {
    const len = path.getTotalLength();
    gsap.set(path, {
      strokeDasharray: len,
      strokeDashoffset: len,
      opacity: 1,
    });
  });

  tl = gsap.timeline();

  tl.to(paths, {
    strokeDashoffset: 0,
    duration: 2,
    stagger: 0.4,
    ease: "power2.inOut",
  })
    .to(overlayRef.value, {
      opacity: 0,
      duration: 0.5,
      ease: "power2.in",
    })
    .call(() => {
      visible.value = false;
    });
});

onUnmounted(() => {
  tl?.kill();
});
</script>

